using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, data structures, and the design of software and hardware systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Exploration of numbers, structures, patterns, and the logical reasoning that underpins scientific discovery." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Investigation of matter, energy, and the fundamental forces that govern the natural world." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Analysis and creation of literary works, critical thinking, and effective communication across diverse contexts." }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, DepartmentId = 1, Title = "Introduction to Programming", Code = "CS 101", Description = "Fundamentals of programming using Python. Topics include variables, control structures, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory computer science and has published extensively on CS education pedagogy.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, Title = "Data Structures and Algorithms", Code = "CS 201", Description = "Study of fundamental data structures (lists, trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. Marcus Rivera", InstructorBio = "Dr. Rivera specializes in algorithm optimization and has contributed to several open-source projects focused on high-performance computing.", IsFeatured = false },
            new() { Id = 3, DepartmentId = 1, Title = "Database Systems", Code = "CS 340", Description = "Relational database design, SQL, normalization, transaction processing, and introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Sarah Kim", InstructorBio = "Dr. Kim worked as a database architect at major tech companies before joining academia. Her research focuses on distributed database systems.", IsFeatured = false },
            new() { Id = 4, DepartmentId = 1, Title = "Artificial Intelligence", Code = "CS 420", Description = "Introduction to AI concepts including search algorithms, machine learning, neural networks, and natural language processing.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory computer science and has published extensively on CS education pedagogy.", IsFeatured = true },

            // Mathematics
            new() { Id = 5, DepartmentId = 2, Title = "Calculus I", Code = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to rates of change, optimization, and area computation.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. James Okafor", InstructorBio = "Dr. Okafor is an award-winning educator known for making advanced mathematical concepts accessible to all students.", IsFeatured = true },
            new() { Id = 6, DepartmentId = 2, Title = "Linear Algebra", Code = "MATH 220", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to systems of equations and geometry.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Elena Vasquez", InstructorBio = "Dr. Vasquez researches applications of linear algebra in quantum computing and cryptography.", IsFeatured = false },
            new() { Id = 7, DepartmentId = 2, Title = "Probability and Statistics", Code = "MATH 360", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis with real-world applications.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:15 PM", InstructorName = "Dr. James Okafor", InstructorBio = "Dr. Okafor is an award-winning educator known for making advanced mathematical concepts accessible to all students.", IsFeatured = false },

            // Physics
            new() { Id = 8, DepartmentId = 3, Title = "General Physics I", Code = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. Robert Tanaka", InstructorBio = "Dr. Tanaka's research focuses on experimental condensed matter physics. He has mentored over 50 undergraduate researchers.", IsFeatured = false },
            new() { Id = 9, DepartmentId = 3, Title = "Electromagnetism", Code = "PHYS 202", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:15 PM + Lab Fri 1:00–3:50 PM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma is a theoretical physicist who has published over 40 papers on electromagnetic theory and photonics.", IsFeatured = true },
            new() { Id = 10, DepartmentId = 3, Title = "Quantum Mechanics", Code = "PHYS 401", Description = "Wave-particle duality, Schrödinger equation, quantum states, and applications to atomic and molecular systems.", Credits = 3, Schedule = "Mon/Wed 3:00–4:15 PM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma is a theoretical physicist who has published over 40 papers on electromagnetic theory and photonics.", IsFeatured = false },

            // English
            new() { Id = 11, DepartmentId = 4, Title = "Composition and Rhetoric", Code = "ENG 101", Description = "Develop effective writing skills through essay composition, argumentation, and rhetorical analysis of diverse texts.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. Diana Holloway", InstructorBio = "Prof. Holloway is a published author and writing coach who has helped thousands of students develop their academic voice.", IsFeatured = false },
            new() { Id = 12, DepartmentId = 4, Title = "American Literature", Code = "ENG 250", Description = "Survey of American literary traditions from the colonial period to the present, exploring themes of identity, freedom, and social change.", Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM", InstructorName = "Dr. William Grant", InstructorBio = "Dr. Grant specializes in 20th-century American fiction and has authored two books on the Harlem Renaissance.", IsFeatured = true },
            new() { Id = 13, DepartmentId = 4, Title = "Creative Writing", Code = "ENG 310", Description = "Workshop-based course in fiction and poetry writing. Students produce original work and provide peer critique.", Credits = 3, Schedule = "Wed 6:00–8:45 PM", InstructorName = "Prof. Diana Holloway", InstructorBio = "Prof. Holloway is a published author and writing coach who has helped thousands of students develop their academic voice.", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetCoursesByDepartment(int deptId) => _courses.Where(c => c.DepartmentId == deptId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> SearchCourses(string query)
    {
        if (string.IsNullOrWhiteSpace(query))
            return _courses;

        var lower = query.ToLowerInvariant();
        return _courses.Where(c =>
            c.Title.ToLowerInvariant().Contains(lower) ||
            c.Code.ToLowerInvariant().Contains(lower) ||
            c.Description.ToLowerInvariant().Contains(lower) ||
            c.InstructorName.ToLowerInvariant().Contains(lower)
        ).ToList();
    }

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        _enrollments.Add(request);
        return true;
    }
}

