@page "/courses"
@rendermode InteractiveServer
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Courses - Greenfield University</PageTitle>

<h1>Course Catalog</h1>

<div class="filters">
    <input type="text" placeholder="Search courses..." @bind="searchQuery" @bind:event="oninput" class="search-input" />
    <select @bind="selectedDepartment" class="filter-select">
        <option value="0">All Departments</option>
        @foreach (var dept in departments)
        {
            <option value="@dept.Id">@dept.Name</option>
        }
    </select>
</div>

<div class="card-grid">
    @foreach (var course in filteredCourses)
    {
        var dept = CatalogService.GetDepartment(course.DepartmentId);
        <div class="card">
            <h3>@course.Title</h3>
            <p class="card-meta"><strong>@course.Code</strong> · @dept?.Name · @course.Credits Credits</p>
            <a href="/courses/@course.Id" class="btn">View Details</a>
        </div>
    }
</div>

@if (!filteredCourses.Any())
{
    <p class="no-results">No courses found matching your criteria.</p>
}

@code {
    private List<Department> departments = new();
    private List<Course> allCourses = new();
    private string searchQuery = string.Empty;
    private int selectedDepartment;

    [SupplyParameterFromQuery(Name = "dept")]
    public int? DeptFilter { get; set; }

    private List<Course> filteredCourses
    {
        get
        {
            var courses = allCourses.AsEnumerable();
            if (selectedDepartment > 0)
                courses = courses.Where(c => c.DepartmentId == selectedDepartment);
            if (!string.IsNullOrWhiteSpace(searchQuery))
            {
                var lower = searchQuery.ToLowerInvariant();
                courses = courses.Where(c =>
                    c.Title.ToLowerInvariant().Contains(lower) ||
                    c.Code.ToLowerInvariant().Contains(lower) ||
                    c.Description.ToLowerInvariant().Contains(lower) ||
                    c.InstructorName.ToLowerInvariant().Contains(lower));
            }
            return courses.ToList();
        }
    }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        allCourses = CatalogService.GetCourses();
        if (DeptFilter.HasValue && DeptFilter.Value > 0)
            selectedDepartment = DeptFilter.Value;
    }
}

@page "/courses/{Id:int}"
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course") - Greenfield University</PageTitle>

@if (course is null)
{
    <p>Course not found.</p>
}
else
{
    var dept = CatalogService.GetDepartment(course.DepartmentId);

    <div class="course-detail">
        <a href="/courses" class="back-link">&larr; Back to Courses</a>

        <h1>@course.Title</h1>
        <p class="card-meta"><strong>@course.Code</strong> · @dept?.Name · @course.Credits Credits</p>

        <section class="detail-section">
            <h2>Description</h2>
            <p>@course.Description</p>
        </section>

        <section class="detail-section">
            <h2>Schedule</h2>
            <p>@course.Schedule</p>
        </section>

        <section class="detail-section">
            <h2>Instructor</h2>
            <h3>@course.InstructorName</h3>
            <p>@course.InstructorBio</p>
        </section>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/departments"
@inject CatalogService CatalogService

<PageTitle>Departments - Greenfield University</PageTitle>

<h1>Academic Departments</h1>

<div class="card-grid">
    @foreach (var dept in departments)
    {
        <div class="card">
            <h3>@dept.Name <span class="dept-code">(@dept.Code)</span></h3>
            <p>@dept.Description</p>
            <a href="/courses?dept=@dept.Id" class="btn">View Courses</a>
        </div>
    }
</div>

@code {
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
    }
}

@page "/enroll"
@rendermode InteractiveServer
@inject CatalogService CatalogService

<PageTitle>Enroll - Greenfield University</PageTitle>

<h1>Course Enrollment</h1>

@if (submitted)
{
    <div class="confirmation">
        <h2>✓ Enrollment Request Submitted</h2>
        <p>Thank you, <strong>@model.Name</strong>! Your enrollment request for the selected course has been received. You will receive a confirmation email shortly.</p>
        <button class="btn" @onclick="Reset">Submit Another Request</button>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" class="enroll-form">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="form-group">
            <label for="name">Full Name</label>
            <InputText id="name" @bind-Value="model.Name" class="form-control" />
            <ValidationMessage For="() => model.Name" />
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <InputText id="studentId" @bind-Value="model.StudentId" class="form-control" />
            <ValidationMessage For="() => model.StudentId" />
        </div>

        <div class="form-group">
            <label for="course">Course</label>
            <InputSelect id="course" @bind-Value="model.CourseId" class="form-control">
                <option value="0">-- Select a Course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.Code - @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment</button>
    </EditForm>
}

@code {
    private EnrollmentRequest model = new();
    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollmentRequest(model);
        submitted = true;
    }

    private void Reset()
    {
        model = new();
        submitted = false;
    }
}

