            if (selectedDepartment > 0)
                courses = courses.Where(c => c.DepartmentId == selectedDepartment);
            if (!string.IsNullOrWhiteSpace(searchQuery))
            {
                var lower = searchQuery.ToLowerInvariant();
                courses = courses.Where(c =>
                    c.Title.ToLowerInvariant().Contains(lower) ||
                    c.Code.ToLowerInvariant().Contains(lower) ||
                    c.Description.ToLowerInvariant().Contains(lower) ||
                    c.InstructorName.ToLowerInvariant().Contains(lower));
            }
            return courses.ToList();
        }
    }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        allCourses = CatalogService.GetCourses();
        if (DeptFilter.HasValue && DeptFilter.Value > 0)
            selectedDepartment = DeptFilter.Value;
    }
}

